from pathlib import Path
OPS = [
    ("w", "docs/operations/BRANCH_RULESET_AUTOMATON3.md", "# Operator action: require Automaton checks on `main`\n\nRepository: `Aegis-Omega/AEGIS-OMEGA`  \nTarget: canonical branch `main` or its merge-queue ruleset\n\nRequired status-check contexts:\n\n- `aegis / automaton-2`\n- `aegis / automaton-3`\n\nRecommended configuration:\n\n- require branches to be up to date before merging;\n- preserve every existing required check and review restriction;\n- enable the same contexts for merge queue / `merge_group` evaluation;\n- prohibit bypass except the existing emergency administrator path, with audit logging;\n- do not mark Vercel account-rate-limit statuses as repository correctness gates.\n\nVerification procedure:\n\n1. Open repository Settings → Rules → Rulesets.\n2. Select the active `main` branch ruleset.\n3. Add both exact context names under required status checks.\n4. Enable strict up-to-date checking and merge-queue compatibility.\n5. Open a test PR and confirm both checks are listed as required.\n6. Attempt a merge while either check is absent or failing; GitHub must deny it.\n\nThis document is an administration instruction, not evidence that the ruleset has been changed.\n"),
    ("w", "docs/operations/LAW_OF_SILENCE_V2.md", "# Law of Silence V2 — mediated agents, visible operator\n\nAgents may not exchange uncontrolled raw peer messages. This restriction never suppresses operator authorization requests, deterministic receipts, security alerts, consequential mutation notices, cancellation state, or failure reporting.\n\nEvery peer-directed message uses `EventEnvelope V1` and binds sender identity, recipient or routing domain, source state, requested capability, typed payload schema, payload digest, provenance, policy decision, parent event, sequence, and receipt reference.\n\nNatural-language text is permitted only in the bounded `payload.text` field. It is data, not authority. Authority-bearing fields reject ambiguous Unicode normalization, control characters, hidden formatting, malformed sequence, stale parent state, sender/lease mismatch, schema drift, oversized content, and digest mismatch.\n\nOperator-visible notifications and receipts are constitutionally privileged observability channels. A coordinator, router, hook, workflow, or agent may not invoke the Law of Silence to hide or delay them.\n"),
    ("w", "docs/security/AUTOMATON3_THREAT_MODEL.md", "# Automaton-3 threat model\n\n## Protected assets\n\nCanonical repository state, constitutional files, capability registry, policy roots, workflow state, database governance state, external side effects, operator approvals, receipts, and attestations.\n\n## Trust boundaries\n\nThe operator, requesting actor, configured model, reviewing model, physical executor, tool process, workflow runner, repository workspace, and external provider are distinct identities. None is inferred from another.\n\n## Primary threats and controls\n\n| Threat | Control | Failure mode |\n|---|---|---|\n| Unknown or documentation-only capability | Evidence registry plus minimum three validated runs | `UNMAPPED_CAPABILITY`, `UNOBSERVED_CAPABILITY`, or `INSUFFICIENT_VALIDATED_RUNS` |\n| Repository or namespace confusion | Canonical remote, real-path root checks, nested-repository selection, path-view reconciliation | workspace denial receipt |\n| Symlink, traversal, mount, UNC, WSL, drive, or case escape | `resolve(strict)` containment and normalized path-view comparison | no mutation |\n| Controller identity conflation | Separate actor, model, session, executor, tool, and workflow fields | invalid identity envelope |\n| Concurrent or stale writers | single active lease, generation, fencing token, expected parent, replay set | deterministic lease denial |\n| Workflow invisibility or orphaning | durable registry, monotone transitions, heartbeat generation, cancellation and orphan state | authority revoked |\n| Retry duplicates | per-execution idempotency keys and terminal-state checks | `DUPLICATE_EXTERNAL_ACTION` |\n| Raw peer instructions becoming authority | typed EventEnvelope, bounded text, payload digest, policy and receipt references | envelope rejected |\n| Unicode/control-character bypass | NFC equality and Unicode control-category rejection in authority fields | identity/event denial |\n| Broken evidence or receipt chain | repository containment, file existence, parent digest, monotone sequence | exact denial code |\n| Authority service outage | no local fallback | `AUTHORITY_SERVICE_UNAVAILABLE` |\n| Operator notification suppression | notifications and receipts are outside peer-message restrictions | constitutional violation |\n\n## Residual risks\n\nThe local lease and durable registry are reference implementations. Multi-host persistence requires a transactional backend that enforces the same compare-and-swap, generation, parent-hash, idempotency, and cancellation contracts. No distributed exact-once claim is made.\n\nGitHub branch-ruleset administration depends on repository administration API access. A tracking issue and exact configuration artifact are required when that interface is unavailable.\n"),
    ("w", "harness/policies/capability-map.v1.json", "{\n  \"schema_version\": \"1.0.0\",\n  \"capabilities\": {\n    \"coordinator.dispatch\": {\"skill_id\": \"orchestration_routing\", \"allowed_action_classes\": [\"D1\"], \"allowed_tools\": [\"agents.coordinator:dispatch\"]},\n    \"mcp.platform.status\": {\"skill_id\": \"python_bridge_development\", \"allowed_action_classes\": [\"D0\"], \"allowed_tools\": [\"aegis_platform_status\"]},\n    \"mcp.execution.read\": {\"skill_id\": \"orchestration_routing\", \"allowed_action_classes\": [\"D0\"], \"allowed_tools\": [\"aegis_get_execution\"]},\n    \"mcp.collaborate\": {\"skill_id\": \"orchestration_routing\", \"allowed_action_classes\": [\"D2\"], \"allowed_tools\": [\"aegis_collaborate\"]},\n    \"mcp.execution.start\": {\"skill_id\": \"orchestration_routing\", \"allowed_action_classes\": [\"D2\"], \"allowed_tools\": [\"aegis_start_execution\"]},\n    \"mcp.claude.call\": {\"skill_id\": \"python_bridge_development\", \"allowed_action_classes\": [\"D3\"], \"allowed_tools\": [\"aegis_governed_claude_call\"]},\n    \"repository.mutate\": {\"skill_id\": \"gate8_deployment_gate\", \"allowed_action_classes\": [\"D2\", \"D4\"], \"allowed_tools\": [\"git\", \"github\"]},\n    \"database.governance.write\": {\"skill_id\": \"audit_trail_management\", \"allowed_action_classes\": [\"D3\", \"D4\"], \"allowed_tools\": [\"supabase\", \"postgres\"]}\n  }\n}\n"),
    ("w", "harness/policies/consequence-policy.v1.json", "{\n  \"schema_version\": \"1.0.0\",\n  \"classes\": {\n    \"D0\": {\"minimum_validated_runs\": 0, \"approval\": \"NONE\", \"workspace\": \"READ_ONLY\", \"replay\": false, \"rollback\": \"NONE\", \"external_idempotency\": false},\n    \"D1\": {\"minimum_validated_runs\": 3, \"approval\": \"NONE\", \"workspace\": \"REPOSITORY\", \"replay\": true, \"rollback\": \"REQUIRED\", \"external_idempotency\": false},\n    \"D2\": {\"minimum_validated_runs\": 3, \"approval\": \"EXPLICIT\", \"workspace\": \"REPOSITORY\", \"replay\": true, \"rollback\": \"REQUIRED\", \"external_idempotency\": false},\n    \"D3\": {\"minimum_validated_runs\": 3, \"approval\": \"EXPLICIT\", \"workspace\": \"REPOSITORY\", \"replay\": true, \"rollback\": \"COMPENSATION_OR_IDEMPOTENCY\", \"external_idempotency\": true},\n    \"D4\": {\"minimum_validated_runs\": 3, \"approval\": \"EXPLICIT\", \"workspace\": \"REPOSITORY\", \"replay\": true, \"rollback\": \"COMPENSATION_OR_IDEMPOTENCY\", \"external_idempotency\": true}\n  }\n}\n"),
    ("w", "harness/sdk/authority_client.py", "\"\"\"Environment-bound client for the single Automaton-3 authority evaluator.\"\"\"\nfrom __future__ import annotations\n\nimport json\nimport os\nfrom dataclasses import asdict\nfrom pathlib import Path\nfrom typing import Any\n\nfrom harness.sdk.sovereign_execution import (\n    ADMITTED, ApprovalGrant, AuthorityEvaluator, AuthorityRequest,\n    ExecutionIdentityEnvelope, ZERO_HASH, canonical_hash,\n    load_capability_registry, load_policy, make_mutation_receipt,\n    verify_workspace,\n)\n\nREPO_ROOT = Path(__file__).resolve().parents[2]\n\n\ndef _denial(code: str, detail: str = \"\") -> dict[str, Any]:\n    body = {\"outcome\": \"DENIED\", \"authority_score\": \"0.000000\", \"denial_codes\": [code], \"detail_digest\": canonical_hash(\"AEGIS_AUTHORITY_CLIENT_DETAIL_V1\", detail)}\n    body[\"decision_root\"] = canonical_hash(\"AEGIS_AUTHORITY_CLIENT_DENIAL_V1\", body)\n    return body\n\n\ndef authorize_from_environment(*, action_class: str, authority_domain: str, requested_capability: str, tool: str, target: str, action: dict[str, Any], current_generation: int = 0, idempotency_key: str = \"NONE\", compensation_reference: str = \"NONE\") -> dict[str, Any]:\n    raw_identity = os.environ.get(\"AEGIS_EXECUTION_IDENTITY_JSON\")\n    if not raw_identity:\n        return _denial(\"IDENTITY_UNAVAILABLE\")\n    try:\n        identity = ExecutionIdentityEnvelope(**json.loads(raw_identity))\n        identity_root = identity.root\n    except Exception as exc:\n        return _denial(\"IDENTITY_INVALID\", str(exc))\n    action_digest = canonical_hash(\"AEGIS_REQUESTED_ACTION_V1\", action)\n    if action_digest != identity.action_digest:\n        return _denial(\"ACTION_DIGEST_MISMATCH\")\n\n    try:\n        observation = json.loads(os.environ.get(\"AEGIS_WORKSPACE_OBSERVATION_JSON\", \"{}\"))\n        workspace = verify_workspace(\n            declared_root=REPO_ROOT,\n            cwd=observation.get(\"actual_cwd\", os.getcwd()),\n            expected_remote=identity.repository_identity,\n            actual_remote=observation.get(\"remote_origin\", identity.repository_identity),\n            project_identity=identity.project_identity,\n            source_commit=identity.source_commit,\n            operator_authorization=identity.approval_reference,\n            mutation_target=observation.get(\"mutation_target\", REPO_ROOT),\n            path_views=observation.get(\"path_views\", {}),\n            selected_nested_root=observation.get(\"selected_nested_root\"),\n        )\n    except Exception as exc:\n        return _denial(\"WORKSPACE_VERIFICATION_ERROR\", str(exc))\n    if workspace.outcome != ADMITTED or workspace.workspace_binding != identity.workspace_binding:\n        return _denial(\"WORKSPACE_DENIED\", \",\".join(workspace.denial_codes))\n\n    try:\n        policy, policy_root = load_policy(REPO_ROOT / \"harness/policies/consequence-policy.v1.json\")\n        registry, registry_root = load_capability_registry(\n            repository_root=REPO_ROOT,\n            skill_tree_path=REPO_ROOT / \"harness/skill_tree.json\",\n            capability_map_path=REPO_ROOT / \"harness/policies/capability-map.v1.json\",\n        )\n    except Exception as exc:\n        return _denial(\"AUTHORITY_SERVICE_UNAVAILABLE\", str(exc))\n\n    approval = None\n    raw_approval = os.environ.get(\"AEGIS_APPROVAL_GRANT_JSON\")\n    if raw_approval:\n        try:\n            approval = ApprovalGrant(**json.loads(raw_approval))\n        except Exception as exc:\n            return _denial(\"APPROVAL_MALFORMED\", str(exc))\n    request = AuthorityRequest(\n        action_class=action_class, authority_domain=authority_domain,\n        requested_capability=requested_capability, tool=tool, target=target,\n        identity_root=identity_root, workspace_binding=identity.workspace_binding,\n        source_commit=identity.source_commit, registry_root=registry_root,\n        policy_root=policy_root, current_generation=current_generation,\n        approval_reference=identity.approval_reference,\n        idempotency_key=idempotency_key, compensation_reference=compensation_reference,\n    )\n    decision = AuthorityEvaluator(policy=policy, registry=registry, repository_root=REPO_ROOT).evaluate(request, approval=approval)\n    receipt = make_mutation_receipt(\n        identity_root=identity_root, workspace_binding=identity.workspace_binding,\n        decision=decision, pre_state_digest=identity.expected_pre_state,\n        action_digest=action_digest, result={\"authority_outcome\": decision.outcome},\n        post_state_digest=identity.expected_pre_state, parent_receipt=ZERO_HASH, sequence=0,\n    )\n    return {\n        \"outcome\": decision.outcome,\n        \"authority_score\": decision.authority_score,\n        \"denial_codes\": list(decision.denial_codes),\n        \"decision_root\": decision.decision_root,\n        \"receipt_root\": receipt.root,\n        \"execution_identity_root\": identity_root,\n        \"workspace_binding\": identity.workspace_binding,\n        \"observation\": asdict(workspace.observation),\n    }\n"),
]
for mode, path, content in OPS:
    target = Path(path)
    target.parent.mkdir(parents=True, exist_ok=True)
    with target.open('w' if mode == 'w' else 'a', encoding='utf-8', newline='') as handle:
        handle.write(content)
